module alu (
  input [3:0] obf_a,
  input [3:0] b,
  input [1:0] op,
  output reg [3:0] result);always @(*) begin
  case (op)
    2'b00: result = obf_a + b;
    2'b01: result = obf_a - b;
    2'b10: result = obf_a & b;
    2'b11: result = obf_a | b;
    default: result = 4'b0000;
  endcase
end

endmodule
